              activeGroupId === group.id
                ? 'bg-primary/10 text-primary border border-primary/20'
                : 'text-gray-400 hover:bg-surface hover:text-gray-200'
            }`}
            onClick={() => onSelectGroup(group.id)}
          >
             <div className="flex items-center gap-3 overflow-hidden">
              <Folder size={16} className={activeGroupId === group.id ? 'fill-primary/20' : ''} />
              <span className="text-sm font-medium truncate">{group.name}</span>
            </div>

            <button
              onClick={(e) => {
                e.stopPropagation();
                if(confirm(`Delete group "${group.name}"?`)) onDeleteGroup(activeProject.id, group.id);
              }}
              className="opacity-0 group-hover:opacity-100 p-1 text-gray-500 hover:text-red-400 transition-opacity"
            >
              <Trash2 size={14} />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ProjectGroup, SecretItem, ItemType } from '../types';
import { Copy, Eye, EyeOff, Plus, Trash2, Check, Terminal, Key, Type, Save } from 'lucide-react';

interface ContentAreaProps {
  group: ProjectGroup | null;
  onAddItem: (item: SecretItem) => void;
  onUpdateItem: (itemId: string, updates: Partial<SecretItem>) => void;
  onDeleteItem: (itemId: string) => void;
}

const ItemCard: React.FC<{
  item: SecretItem;
  onCopy: (val: string) => void;
  onDelete: () => void;
  onUpdate: (updates: Partial<SecretItem>) => void;
}> = ({ item, onCopy, onDelete, onUpdate }) => {
  const [revealed, setRevealed] = useState(false);
  const [copied, setCopied] = useState(false);
  const [isEditing, setIsEditing] = useState(false);

  // Local edit state
  const [editLabel, setEditLabel] = useState(item.label);
  const [editValue, setEditValue] = useState(item.value);

  const handleCopy = () => {
    onCopy(item.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSave = () => {
    onUpdate({ label: editLabel, value: editValue });
    setIsEditing(false);
  };

  // Icons based on type
  const TypeIcon = item.type === 'code' ? Terminal : item.type === 'password' ? Key : Type;

  if (isEditing) {
    return (
        <div className="bg-surface border border-primary/50 rounded-lg p-4 mb-3 shadow-lg animate-in fade-in zoom-in-95 duration-200">
            <div className="flex flex-col gap-3">
                <input 
                    value={editLabel} 
                    onChange={e => setEditLabel(e.target.value)}
                    className="bg-background border border-border rounded px-2 py-1 text-sm text-white focus:border-primary focus:outline-none"
                    placeholder="Label"
                />
                <textarea 
                    value={editValue} 
                    onChange={e => setEditValue(e.target.value)}
                    className="bg-background border border-border rounded px-2 py-1 text-sm text-gray-300 font-mono h-24 focus:border-primary focus:outline-none resize-none"
                    placeholder="Value"
                />
                <div className="flex justify-end gap-2">
                    <button onClick={() => setIsEditing(false)} className="text-xs px-3 py-1 rounded hover:bg-white/5 text-gray-400">Cancel</button>
                    <button onClick={handleSave} className="flex items-center gap-1 text-xs bg-primary hover:bg-blue-600 text-white px-3 py-1 rounded">
                        <Save size={14}/> Save
                    </button>
                </div>
            </div>
        </div>
    )
  }

  return (
    <div className="group bg-surface hover:bg-[#253248] border border-border hover:border-primary/30 rounded-lg p-4 mb-3 transition-all shadow-sm">
      <div className="flex items-start justify-between mb-2">
        <div className="flex items-center gap-2 text-gray-400 group-hover:text-primary transition-colors">
            <TypeIcon size={14} />
            <h3 className="text-sm font-semibold select-none">{item.label}</h3>
        </div>
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
           <button 
                onClick={() => setIsEditing(true)} 
                className="p-1.5 text-gray-500 hover:text-white rounded hover:bg-white/10"
                title="Edit Item"
            >
                <Type size={14} />
            </button>
            <button 
                onClick={(e) => {
                    if(confirm('Delete this item?')) onDelete();
                }}
                className="p-1.5 text-gray-500 hover:text-red-400 rounded hover:bg-red-400/10"
                title="Delete Item"
            >
                <Trash2 size={14} />
            </button>
        </div>
      </div>

      <div className="relative bg-background rounded border border-border group-hover:border-gray-600 transition-colors">
        <div 
            className={`p-3 font-mono text-sm break-all pr-24 ${item.type === 'code' ? 'text-green-400 whitespace-pre-wrap' : 'text-gray-300'}`}
        >
          {item.type === 'password' && !revealed 
            ? '•'.repeat(Math.min(item.value.length, 24) || 8) 
            : item.value}
        </div>

        <div className="absolute top-1 right-1 flex items-center bg-background/80 backdrop-blur-sm rounded p-1">
          {item.type === 'password' && (
            <button
              onClick={() => setRevealed(!revealed)}
              className="p-1.5 text-gray-400 hover:text-white rounded hover:bg-white/10 transition-colors mr-1"
              title={revealed ? "Hide" : "Show"}
            >
              {revealed ? <EyeOff size={16} /> : <Eye size={16} />}
            </button>
          )}

          <button
            onClick={handleCopy}
            className={`flex items-center gap-1.5 px-2 py-1.5 rounded transition-all ${
                copied 
                ? 'bg-green-500/20 text-green-400' 
                : 'text-gray-400 hover:text-white hover:bg-primary/20 hover:text-primary'
            }`}
            title="Copy to clipboard"
          >
            {copied ? <Check size={16} /> : <Copy size={16} />}
            <span className="text-xs font-bold uppercase">{copied ? 'Copied' : 'Copy'}</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export const ContentArea: React.FC<ContentAreaProps> = ({ 
    group, 
    onAddItem, 
    onDeleteItem,
    onUpdateItem
}) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newItemLabel, setNewItemLabel] = useState('');
  const [newItemValue, setNewItemValue] = useState('');
  const [newItemType, setNewItemType] = useState<ItemType>('text');

  // Reset form when group changes
  useEffect(() => {
    setIsAdding(false);
    setNewItemLabel('');
    setNewItemValue('');
  }, [group?.id]);

  if (!group) {
    return (
      <div className="flex-1 h-full bg-background flex items-center justify-center p-8">
        <div className="text-center max-w-md">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-surface mb-6">
                <Terminal size={32} className="text-gray-600" />
            </div>
            <h1 className="text-2xl font-bold text-gray-300 mb-2">Welcome to ConfigVault</h1>
            <p className="text-gray-500 mb-8">Select a project and a group from the sidebar to view or manage your configuration secrets.</p>
        </div>
      </div>
    );
  }

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const handleAddItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (newItemLabel && newItemValue) {
      onAddItem({
        id: crypto.randomUUID(),
        label: newItemLabel,
        value: newItemValue,
        type: newItemType
      });
      setNewItemLabel('');
      setNewItemValue('');
      setIsAdding(false);
    }
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-background relative">
      {/* Header */}
      <div className="p-6 pb-4 border-b border-border flex items-center justify-between sticky top-0 bg-background/95 backdrop-blur z-10">
        <div>
           <div className="flex items-center gap-2 text-xs text-gray-500 uppercase tracking-widest mb-1">
                <span>Secret List</span>
                <span>/</span>
                <span className="text-primary">{group.name}</span>
           </div>
           <h1 className="text-xl font-bold text-white">{group.name}</h1>
        </div>

        <button
            onClick={() => setIsAdding(!isAdding)}
            className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${
                isAdding 
                ? 'bg-gray-700 text-gray-300 hover:bg-gray-600' 
                : 'bg-primary text-white hover:bg-blue-600 shadow-lg shadow-blue-900/20'
            }`}
        >
            {isAdding ? 'Cancel' : (
                <>
                    <Plus size={18} />
                    <span>New Item</span>
                </>
            )}
        </button>
      </div>

      {/* Content Scroll Area */}
      <div className="flex-1 overflow-y-auto p-6">

        {/* Add Form */}
        {isAdding && (
          <form onSubmit={handleAddItem} className="bg-surface/50 border border-primary border-dashed rounded-lg p-4 mb-6 animate-in slide-in-from-top-4 fade-in duration-300">
             <div className="flex items-center gap-4 mb-3">
                 <div className="flex-1">
                     <label className="block text-xs text-gray-500 mb-1">Label</label>
                     <input 
                        autoFocus
                        required
                        className="w-full bg-background border border-border rounded px-3 py-2 text-sm focus:border-primary focus:outline-none"
                        placeholder="e.g. DATABASE_URL"
                        value={newItemLabel}
                        onChange={e => setNewItemLabel(e.target.value)}
                     />
                 </div>
                 <div className="w-1/3">
                    <label className="block text-xs text-gray-500 mb-1">Type</label>
                     <div className="flex bg-background border border-border rounded p-1">
                        {(['text', 'password', 'code'] as ItemType[]).map(t => (
                            <button
                                key={t}
                                type="button"
                                onClick={() => setNewItemType(t)}
                                className={`flex-1 text-xs py-1.5 rounded capitalize ${newItemType === t ? 'bg-surface text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}
                            >
                                {t}
                            </button>
                        ))}
                     </div>
                 </div>
             </div>

             <div className="mb-4">
                <label className="block text-xs text-gray-500 mb-1">Value</label>
                <textarea 
                    required
                    className="w-full bg-background border border-border rounded px-3 py-2 text-sm font-mono h-20 focus:border-primary focus:outline-none resize-none"
                    placeholder="Enter the secret value or snippet here..."
                    value={newItemValue}
                    onChange={e => setNewItemValue(e.target.value)}
                />
             </div>

             <div className="flex justify-end">
                 <button type="submit" className="bg-primary hover:bg-blue-600 text-white px-4 py-1.5 rounded text-sm font-medium transition-colors">
                     Add Secret
                 </button>
             </div>
          </form>
        )}

        {/* List */}
        <div className="space-y-2">
            {group.items.length === 0 && !isAdding && (
                <div className="flex flex-col items-center justify-center py-12 text-gray-500 border-2 border-dashed border-border rounded-xl">
                    <Key size={32} className="mb-3 opacity-20" />
                    <p>No secrets in this group yet.</p>
                </div>
            )}

            {group.items.map(item => (
                <ItemCard 
                    key={item.id} 
                    item={item} 
                    onCopy={handleCopy} 
                    onDelete={() => onDeleteItem(item.id)}
                    onUpdate={(updates) => onUpdateItem(item.id, updates)}
                />
            ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { SidebarProjects } from './components/SidebarProjects';
import { SidebarGroups } from './components/SidebarGroups';
import { ContentArea } from './components/ContentArea';
import { Project, ProjectGroup, SecretItem } from './types';
import { INITIAL_DATA } from './constants';
import { Menu, X } from 'lucide-react';

const LOCAL_STORAGE_KEY = 'config-vault-data-v1';

export default function App() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
  const [activeGroupId, setActiveGroupId] = useState<string | null>(null);

  // Mobile nav state
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  // Load Data
  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        setProjects(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved data", e);
        setProjects(INITIAL_DATA);
      }
    } else {
      setProjects(INITIAL_DATA);
    }
  }, []);

  // Save Data
  useEffect(() => {
    if (projects.length > 0) {
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Set initial active states if data exists and nothing selected
  useEffect(() => {
    if (projects.length > 0 && !activeProjectId) {
      setActiveProjectId(projects[0].id);
    }
  }, [projects, activeProjectId]);

  useEffect(() => {
    const activeProj = projects.find(p => p.id === activeProjectId);
    if (activeProj && activeProj.groups.length > 0 && !activeGroupId) {
      setActiveGroupId(activeProj.groups[0].id);
    } else if (activeProj && activeProj.groups.length === 0) {
        setActiveGroupId(null);
    }
  }, [activeProjectId, projects]); // Depend on projects to auto-select new groups

  // --- Actions ---

  const addProject = (name: string) => {
    const newProject: Project = {
      id: crypto.randomUUID(),
      name,
      icon: 'Box', // Default icon
      groups: []
    };
    setProjects([...projects, newProject]);
    setActiveProjectId(newProject.id);
  };

  const deleteProject = (id: string) => {
    setProjects(projects.filter(p => p.id !== id));
    if (activeProjectId === id) setActiveProjectId(null);
  };

  const addGroup = (name: string) => {
    if (!activeProjectId) return;
    const newGroup: ProjectGroup = {
      id: crypto.randomUUID(),
      name,
      items: []
    };
    setProjects(projects.map(p => {
      if (p.id === activeProjectId) {
        return { ...p, groups: [...p.groups, newGroup] };
      }
      return p;
    }));
    setActiveGroupId(newGroup.id);
  };

  const deleteGroup = (projectId: string, groupId: string) => {
    setProjects(projects.map(p => {
        if (p.id === projectId) {
            return { ...p, groups: p.groups.filter(g => g.id !== groupId) };
        }
        return p;
    }));
    if (activeGroupId === groupId) setActiveGroupId(null);
  };

  const addItem = (item: SecretItem) => {
    if (!activeProjectId || !activeGroupId) return;
    setProjects(projects.map(p => {
      if (p.id === activeProjectId) {
        const updatedGroups = p.groups.map(g => {
          if (g.id === activeGroupId) {
            return { ...g, items: [...g.items, item] };
          }
          return g;
        });
        return { ...p, groups: updatedGroups };
      }
      return p;
    }));
  };

  const deleteItem = (itemId: string) => {
    if (!activeProjectId || !activeGroupId) return;
    setProjects(projects.map(p => {
        if (p.id === activeProjectId) {
            const updatedGroups = p.groups.map(g => {
                if (g.id === activeGroupId) {
                    return { ...g, items: g.items.filter(i => i.id !== itemId) };
                }
                return g;
            });
            return { ...p, groups: updatedGroups };
        }
        return p;
    }));
  };

  const updateItem = (itemId: string, updates: Partial<SecretItem>) => {
    if (!activeProjectId || !activeGroupId) return;
    setProjects(projects.map(p => {
        if (p.id === activeProjectId) {
            const updatedGroups = p.groups.map(g => {
                if (g.id === activeGroupId) {
                    const newItems = g.items.map(i => i.id === itemId ? { ...i, ...updates } : i);
                    return { ...g, items: newItems };
                }
                return g;
            });
            return { ...p, groups: updatedGroups };
        }
        return p;
    }));
  };

  // --- Derived State ---
  const activeProject = projects.find(p => p.id === activeProjectId) || null;
  const activeGroup = activeProject?.groups.find(g => g.id === activeGroupId) || null;

  return (
    <div className="flex flex-col md:flex-row h-screen w-full bg-background text-slate-200 overflow-hidden">

      {/* Mobile Header */}
      <div className="md:hidden flex items-center justify-between p-4 border-b border-border bg-surface">
        <span className="font-bold text-lg">ConfigVault</span>
        <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="p-2">
           {mobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Main Layout Area */}
      <div className={`
        fixed inset-0 z-40 bg-background md:relative md:flex md:w-auto
        transform transition-transform duration-300 ease-in-out
        ${mobileMenuOpen ? 'translate-x-0 pt-16' : '-translate-x-full pt-0'}
        md:translate-x-0 md:pt-0
        flex flex-col md:flex-row
      `}>
          <SidebarProjects 
            projects={projects} 
            activeProjectId={activeProjectId} 
            onSelectProject={(id) => { setActiveProjectId(id); setActiveGroupId(null); if(window.innerWidth < 768) setMobileMenuOpen(false); }}
            onAddProject={addProject}
            onDeleteProject={deleteProject}
          />

          <SidebarGroups 
            activeProject={activeProject}
            activeGroupId={activeGroupId}
            onSelectGroup={(id) => { setActiveGroupId(id); if(window.innerWidth < 768) setMobileMenuOpen(false); }}
            onAddGroup={addGroup}
            onDeleteGroup={deleteGroup}
          />
      </div>

      {/* Content Area (Always visible on desktop, visible under menu on mobile) */}
      <div className="flex-1 h-full overflow-hidden relative z-0">
          <ContentArea 
            group={activeGroup} 
            onAddItem={addItem}
            onDeleteItem={deleteItem}
            onUpdateItem={updateItem}
          />
      </div>

    </div>
  );
}

