import React, { useState, useEffect } from 'react';
import { ProjectGroup, SecretItem, ItemType } from '../types';
import { Copy, Eye, EyeOff, Plus, Trash2, Check, Terminal, Key, Type, Save, LayoutGrid, List } from 'lucide-react';

interface ContentAreaProps {
  group: ProjectGroup | null;
  onAddItem: (item: SecretItem) => void;
  onUpdateItem: (itemId: string, updates: Partial<SecretItem>) => void;
  onDeleteItem: (itemId: string) => void;
}

const ItemCard: React.FC<{
  item: SecretItem;
  onCopy: (val: string) => void;
  onDelete: () => void;
  onUpdate: (updates: Partial<SecretItem>) => void;
  isGridView: boolean;
}> = ({ item, onCopy, onDelete, onUpdate, isGridView }) => {
  const [revealed, setRevealed] = useState(false);
  const [copied, setCopied] = useState(false);
  const [isEditing, setIsEditing] = useState(false);

  // Local edit state
  const [editLabel, setEditLabel] = useState(item.label);
  const [editValue, setEditValue] = useState(item.value);

  const handleCopy = () => {
    onCopy(item.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSave = () => {
    onUpdate({ label: editLabel, value: editValue });
    setIsEditing(false);
  };

  // Icons based on type
  const TypeIcon = item.type === 'code' ? Terminal : item.type === 'password' ? Key : Type;

  if (isEditing) {
    return (
        <div className={`bg-surface border border-primary/50 rounded-lg p-4 shadow-lg animate-in fade-in zoom-in-95 duration-200 ${isGridView ? 'col-span-1' : 'mb-3'}`}>
            <div className="flex flex-col gap-3">
                <input 
                    value={editLabel} 
                    onChange={e => setEditLabel(e.target.value)}
                    className="bg-background border border-border rounded px-2 py-1 text-sm text-white focus:border-primary focus:outline-none"
                    placeholder="名称"
                />
                <textarea 
                    value={editValue} 
                    onChange={e => setEditValue(e.target.value)}
                    className="bg-background border border-border rounded px-2 py-1 text-sm text-gray-300 font-mono h-24 focus:border-primary focus:outline-none resize-none"
                    placeholder="内容"
                />
                <div className="flex justify-end gap-2">
                    <button onClick={() => setIsEditing(false)} className="text-xs px-3 py-1 rounded hover:bg-white/5 text-gray-400">取消</button>
                    <button onClick={handleSave} className="flex items-center gap-1 text-xs bg-primary hover:bg-blue-600 text-white px-3 py-1 rounded">
                        <Save size={14}/> 保存
                    </button>
                </div>
            </div>
        </div>
    )
  }

  return (
    <div className={`group bg-surface hover:bg-[#253248] border border-border hover:border-primary/30 rounded-lg p-4 transition-all shadow-sm flex flex-col ${isGridView ? 'h-full' : 'mb-3'}`}>
      <div className="flex items-start justify-between mb-2">
        <div className="flex items-center gap-2 text-gray-400 group-hover:text-primary transition-colors overflow-hidden">
            <TypeIcon size={14} className="flex-shrink-0"/>
            <h3 className="text-sm font-semibold select-none truncate" title={item.label}>{item.label}</h3>
        </div>
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0 ml-2">
           <button 
                onClick={() => setIsEditing(true)} 
                className="p-1.5 text-gray-500 hover:text-white rounded hover:bg-white/10"
                title="编辑"
            >
                <Type size={14} />
            </button>
            <button 
                onClick={(e) => {
                    if(confirm('确定要删除此项吗?')) onDelete();
                }}
                className="p-1.5 text-gray-500 hover:text-red-400 rounded hover:bg-red-400/10"
                title="删除"
            >
                <Trash2 size={14} />
            </button>
        </div>
      </div>

      <div className="relative bg-background rounded border border-border group-hover:border-gray-600 transition-colors flex-1 flex flex-col min-h-[3rem]">
        <div 
            className={`p-3 font-mono text-sm break-all pr-24 ${
                item.type === 'code' ? 'text-green-400 whitespace-pre-wrap' : 'text-gray-300'
            } ${isGridView ? 'overflow-y-auto max-h-48 custom-scrollbar' : ''}`}
        >
          {item.type === 'password' && !revealed 
            ? '•'.repeat(Math.min(item.value.length, 24) || 8) 
            : item.value}
        </div>

        <div className="absolute top-1 right-1 flex items-center bg-background/80 backdrop-blur-sm rounded p-1">
          {item.type === 'password' && (
            <button
              onClick={() => setRevealed(!revealed)}
              className="p-1.5 text-gray-400 hover:text-white rounded hover:bg-white/10 transition-colors mr-1"
              title={revealed ? "隐藏" : "显示"}
            >
              {revealed ? <EyeOff size={16} /> : <Eye size={16} />}
            </button>
          )}

          <button
            onClick={handleCopy}
            className={`flex items-center gap-1.5 px-2 py-1.5 rounded transition-all ${
                copied 
                ? 'bg-green-500/20 text-green-400' 
                : 'text-gray-400 hover:text-white hover:bg-primary/20 hover:text-primary'
            }`}
            title="复制到剪贴板"
          >
            {copied ? <Check size={16} /> : <Copy size={16} />}
            <span className="text-xs font-bold uppercase">{copied ? '已复制' : '复制'}</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export const ContentArea: React.FC<ContentAreaProps> = ({ 
    group, 
    onAddItem, 
    onDeleteItem,
    onUpdateItem
}) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newItemLabel, setNewItemLabel] = useState('');
  const [newItemValue, setNewItemValue] = useState('');
  const [newItemType, setNewItemType] = useState<ItemType>('text');
  const [isGridView, setIsGridView] = useState(true);

  // Reset form when group changes
  useEffect(() => {
    setIsAdding(false);
    setNewItemLabel('');
    setNewItemValue('');
  }, [group?.id]);

  if (!group) {
    return (
      <div className="flex-1 h-full bg-background flex items-center justify-center p-8">
        <div className="text-center max-w-md">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-surface mb-6">
