        </div>
      </div>
    );
  }

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const handleAddItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (newItemLabel && newItemValue) {
      onAddItem({
        id: crypto.randomUUID(),
        label: newItemLabel,
        value: newItemValue,
        type: newItemType
      });
      setNewItemLabel('');
      setNewItemValue('');
      setIsAdding(false);
    }
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-background relative">
      {/* Header */}
      <div className="p-6 pb-4 border-b border-border flex items-center justify-between sticky top-0 bg-background/95 backdrop-blur z-10 gap-4">
        <div className="flex-1 overflow-hidden">
           <div className="flex items-center gap-2 text-xs text-gray-500 uppercase tracking-widest mb-1">
                <span>配置列表</span>
                <span>/</span>
                <span className="text-primary truncate">{group.name}</span>
           </div>
           <h1 className="text-xl font-bold text-white truncate">{group.name}</h1>
        </div>

        <div className="flex items-center gap-2 flex-shrink-0">
            {/* View Toggle */}
            <div className="bg-surface border border-border rounded-lg p-1 flex items-center">
                <button
                    onClick={() => setIsGridView(false)}
                    className={`p-1.5 rounded transition-colors ${!isGridView ? 'bg-primary text-white shadow' : 'text-gray-400 hover:text-white'}`}
                    title="列表视图"
                >
                    <List size={18} />
                </button>
                <button
                    onClick={() => setIsGridView(true)}
                    className={`p-1.5 rounded transition-colors ${isGridView ? 'bg-primary text-white shadow' : 'text-gray-400 hover:text-white'}`}
                    title="网格视图"
                >
                    <LayoutGrid size={18} />
                </button>
            </div>

            <button
                onClick={() => setIsAdding(!isAdding)}
                className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${
                    isAdding 
                    ? 'bg-gray-700 text-gray-300 hover:bg-gray-600' 
                    : 'bg-primary text-white hover:bg-blue-600 shadow-lg shadow-blue-900/20'
                }`}
            >
                {isAdding ? '取消' : (
                    <>
                        <Plus size={18} />
                        <span className="hidden sm:inline">新建</span>
                    </>
                )}
            </button>
        </div>
      </div>

      {/* Content Scroll Area */}
      <div className="flex-1 overflow-y-auto p-6">

        {/* Add Form */}
        {isAdding && (
          <form onSubmit={handleAddItem} className="bg-surface/50 border border-primary border-dashed rounded-lg p-4 mb-6 animate-in slide-in-from-top-4 fade-in duration-300">
             <div className="flex flex-col md:flex-row items-start md:items-center gap-4 mb-3">
                 <div className="flex-1 w-full">
                     <label className="block text-xs text-gray-500 mb-1">名称</label>
                     <input 
                        autoFocus
                        required
                        className="w-full bg-background border border-border rounded px-3 py-2 text-sm focus:border-primary focus:outline-none"
                        placeholder="例如：DATABASE_URL"
                        value={newItemLabel}
                        onChange={e => setNewItemLabel(e.target.value)}
                     />
                 </div>
                 <div className="w-full md:w-1/3">
                    <label className="block text-xs text-gray-500 mb-1">类型</label>
                     <div className="flex bg-background border border-border rounded p-1">
                        {(['text', 'password', 'code'] as ItemType[]).map(t => (
                            <button
                                key={t}
                                type="button"
                                onClick={() => setNewItemType(t)}
                                className={`flex-1 text-xs py-1.5 rounded capitalize ${newItemType === t ? 'bg-surface text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}
                            >
                                {t}
                            </button>
                        ))}
                     </div>
                 </div>
             </div>

             <div className="mb-4">
                <label className="block text-xs text-gray-500 mb-1">内容</label>
                <textarea 
                    required
                    className="w-full bg-background border border-border rounded px-3 py-2 text-sm font-mono h-20 focus:border-primary focus:outline-none resize-none"
                    placeholder="在此输入密钥值或代码片段..."
                    value={newItemValue}
                    onChange={e => setNewItemValue(e.target.value)}
                />
             </div>

             <div className="flex justify-end">
                 <button type="submit" className="bg-primary hover:bg-blue-600 text-white px-4 py-1.5 rounded text-sm font-medium transition-colors">
                     添加
