            ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ProjectGroup, SecretItem, ItemType } from '../types';
import { Copy, Eye, EyeOff, Plus, Trash2, Check, Terminal, Key, Type, Save, LayoutGrid, List, Sparkles, X, ArrowRight } from 'lucide-react';

interface ContentAreaProps {
  group: ProjectGroup | null;
  onAddItem: (item: SecretItem) => void;
  onUpdateItem: (itemId: string, updates: Partial<SecretItem>) => void;
  onDeleteItem: (itemId: string) => void;
}

// --- Smart Import Logic ---
interface ParsedItem {
    label: string;
    value: string;
    type: ItemType;
}

const parseBlobToItems = (text: string): ParsedItem[] => {
    const results: ParsedItem[] = [];
    const seen = new Set<string>();

    // 1. Try JSON parsing first
    try {
        const json = JSON.parse(text);
        if (typeof json === 'object' && json !== null) {
            Object.entries(json).forEach(([key, val]) => {
                if (typeof val === 'string' || typeof val === 'number' || typeof val === 'boolean') {
                    results.push({
                        label: key,
                        value: String(val),
                        type: key.toLowerCase().includes('key') || key.toLowerCase().includes('secret') || key.toLowerCase().includes('password') ? 'password' : 'text'
                    });
                    seen.add(key);
                }
            });
            return results;
        }
    } catch (e) {
        // Not JSON, continue to regex
    }

    // 2. Line-by-line Heuristic Parsing (.env style, yaml style, simple text)
    const lines = text.split('\n');
    const keyValRegex = /^\s*(?:export\s+)?(?:["']?)([^=:]+?)(?:["']?)\s*[:=]\s*(.*)$/;

    for (let line of lines) {
        line = line.trim();
        if (!line || line.startsWith('#') || line.startsWith('//')) continue;

        const match = line.match(keyValRegex);
        if (match) {
            let label = match[1].trim();
            let value = match[2].trim();

            // Cleanup quotes around value if they exist
            if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
                value = value.slice(1, -1);
            }
            // Cleanup comma at the end (common in JSON/JS objects pasted as text)
            if (value.endsWith(',')) {
                value = value.slice(0, -1);
            }

            if (label && value && !seen.has(label)) {
                 // Intelligent type guessing
                 let type: ItemType = 'text';
                 const lowerLabel = label.toLowerCase();
                 if (lowerLabel.includes('key') || lowerLabel.includes('secret') || lowerLabel.includes('password') || lowerLabel.includes('token') || lowerLabel.includes('auth')) {
                     type = 'password';
                 } else if (value.includes(' ') || value.length > 50 || value.includes('\n')) {
                     // Long values or commands are likely code/text
                     type = value.startsWith('http') ? 'text' : 'code';
                 }

                 results.push({ label, value, type });
                 seen.add(label);
            }
        }
    }

    return results;
};

// --- Sub Components ---

const ImportModal: React.FC<{
    isOpen: boolean;
    onClose: () => void;
    onImport: (items: ParsedItem[]) => void;
}> = ({ isOpen, onClose, onImport }) => {
    const [text, setText] = useState('');
    const [preview, setPreview] = useState<ParsedItem[]>([]);

    useEffect(() => {
        if (text) {
            setPreview(parseBlobToItems(text));
        } else {
            setPreview([]);
        }
    }, [text]);

    if (!isOpen) return null;

    const handleConfirm = () => {
        onImport(preview);
        setText('');
        onClose();
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
            <div className="bg-[#1e293b] border border-border rounded-xl shadow-2xl w-full max-w-2xl flex flex-col max-h-[90vh]">
                <div className="flex items-center justify-between p-4 border-b border-border">
                    <div className="flex items-center gap-2 text-primary">
                        <Sparkles size={20} />
                        <h2 className="font-bold text-white">智能批量导入</h2>
                    </div>
                    <button onClick={onClose} className="text-gray-400 hover:text-white p-1 rounded-md hover:bg-white/10">
                        <X size={20} />
                    </button>
                </div>

                <div className="p-4 flex-1 overflow-hidden flex flex-col md:flex-row gap-4">
                    <div className="flex-1 flex flex-col min-h-[200px]">
                        <label className="text-xs text-gray-400 mb-2 block">粘贴原始文本 (支持 .env, JSON, Key=Value)</label>
                        <textarea
                            autoFocus
                            className="flex-1 w-full bg-[#0f172a] border border-border rounded-lg p-3 text-xs font-mono text-gray-300 focus:outline-none focus:border-primary resize-none"
                            placeholder={`示例:\nDB_HOST=localhost\nAPI_KEY=sk-123456\n# 或者 JSON\n{"APP_ID": "xyz"}`}
                            value={text}
                            onChange={(e) => setText(e.target.value)}
                        />
                    </div>

                    {text && (
                        <div className="md:w-1/2 flex flex-col border-l border-border md:pl-4 mt-4 md:mt-0">
                            <div className="flex items-center justify-between mb-2">
                                <label className="text-xs text-gray-400">识别预览 ({preview.length})</label>
                            </div>
                            <div className="flex-1 overflow-y-auto bg-[#0f172a]/50 rounded-lg border border-border p-2 space-y-2 max-h-[300px] custom-scrollbar">
                                {preview.length === 0 ? (
                                    <div className="text-gray-500 text-xs text-center py-10">无法识别有效键值对</div>
                                ) : (
                                    preview.map((item, idx) => (
                                        <div key={idx} className="flex items-center gap-2 bg-[#1e293b] p-2 rounded border border-border/50">
                                            <div className="flex-1 min-w-0">
                                                <div className="text-xs font-bold text-white truncate">{item.label}</div>
                                                <div className="text-[10px] text-gray-400 truncate">{item.type === 'password' ? '••••••' : item.value}</div>
                                            </div>
                                            <span className="text-[10px] uppercase bg-primary/20 text-primary px-1 rounded">{item.type}</span>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    )}
                </div>

                <div className="p-4 border-t border-border flex justify-end gap-3">
                     <button onClick={onClose} className="px-4 py-2 text-sm text-gray-300 hover:text-white transition-colors">取消</button>
                     <button 
                        onClick={handleConfirm} 
                        disabled={preview.length === 0}
                        className="flex items-center gap-2 bg-primary hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed text-white px-6 py-2 rounded-md text-sm font-medium transition-colors shadow-lg shadow-blue-900/20"
                    >
                        <span>确认导入</span>
                        <ArrowRight size={16} />
                     </button>
                </div>
            </div>
        </div>
    );
};


const ItemCard: React.FC<{
  item: SecretItem;
  onCopy: (val: string) => void;
  onDelete: () => void;
  onUpdate: (updates: Partial<SecretItem>) => void;
  isGridView: boolean;
}> = ({ item, onCopy, onDelete, onUpdate, isGridView }) => {
  const [revealed, setRevealed] = useState(false);
  const [copied, setCopied] = useState(false);
  const [isEditing, setIsEditing] = useState(false);

  // Local edit state
  const [editLabel, setEditLabel] = useState(item.label);
  const [editValue, setEditValue] = useState(item.value);

  const handleCopy = () => {
    onCopy(item.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSave = () => {
    onUpdate({ label: editLabel, value: editValue });
    setIsEditing(false);
  };

  // Icons based on type
  const TypeIcon = item.type === 'code' ? Terminal : item.type === 'password' ? Key : Type;

  if (isEditing) {
    return (
        <div className={`bg-surface border border-primary/50 rounded-lg p-4 shadow-lg animate-in fade-in zoom-in-95 duration-200 ${isGridView ? 'col-span-1' : 'mb-3'}`}>
            <div className="flex flex-col gap-3">
                <input 
                    value={editLabel} 
                    onChange={e => setEditLabel(e.target.value)}
                    className="bg-background border border-border rounded px-2 py-1 text-sm text-white focus:border-primary focus:outline-none"
                    placeholder="名称"
                />
                <textarea 
                    value={editValue} 
                    onChange={e => setEditValue(e.target.value)}
                    className="bg-background border border-border rounded px-2 py-1 text-sm text-gray-300 font-mono h-24 focus:border-primary focus:outline-none resize-none"
                    placeholder="内容"
                />
                <div className="flex justify-end gap-2">
                    <button onClick={() => setIsEditing(false)} className="text-xs px-3 py-1 rounded hover:bg-white/5 text-gray-400">取消</button>
                    <button onClick={handleSave} className="flex items-center gap-1 text-xs bg-primary hover:bg-blue-600 text-white px-3 py-1 rounded">
                        <Save size={14}/> 保存
                    </button>
                </div>
            </div>
        </div>
    )
  }

  return (
    <div className={`group bg-surface hover:bg-[#253248] border border-border hover:border-primary/30 rounded-lg p-4 transition-all shadow-sm flex flex-col ${isGridView ? 'h-full' : 'mb-3'}`}>
      <div className="flex items-start justify-between mb-2">
        <div className="flex items-center gap-2 text-gray-400 group-hover:text-primary transition-colors overflow-hidden">
            <TypeIcon size={14} className="flex-shrink-0"/>
            <h3 className="text-sm font-semibold select-none truncate" title={item.label}>{item.label}</h3>
        </div>
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0 ml-2">
           <button 
                onClick={() => setIsEditing(true)} 
                className="p-1.5 text-gray-500 hover:text-white rounded hover:bg-white/10"
                title="编辑"
            >
                <Type size={14} />
            </button>
            <button 
                onClick={(e) => {
                    if(confirm('确定要删除此项吗?')) onDelete();
                }}
                className="p-1.5 text-gray-500 hover:text-red-400 rounded hover:bg-red-400/10"
                title="删除"
            >
                <Trash2 size={14} />
            </button>
        </div>
      </div>

      <div className="relative bg-background rounded border border-border group-hover:border-gray-600 transition-colors flex-1 flex flex-col min-h-[3rem]">
        <div 
            className={`p-3 font-mono text-sm break-all pr-24 ${
                item.type === 'code' ? 'text-green-400 whitespace-pre-wrap' : 'text-gray-300'
            } ${isGridView ? 'overflow-y-auto max-h-48 custom-scrollbar' : ''}`}
        >
          {item.type === 'password' && !revealed 
            ? '•'.repeat(Math.min(item.value.length, 24) || 8) 
            : item.value}
        </div>

        <div className="absolute top-1 right-1 flex items-center bg-background/80 backdrop-blur-sm rounded p-1">
          {item.type === 'password' && (
            <button
              onClick={() => setRevealed(!revealed)}
              className="p-1.5 text-gray-400 hover:text-white rounded hover:bg-white/10 transition-colors mr-1"
              title={revealed ? "隐藏" : "显示"}
            >
              {revealed ? <EyeOff size={16} /> : <Eye size={16} />}
            </button>
          )}

          <button
            onClick={handleCopy}
            className={`flex items-center gap-1.5 px-2 py-1.5 rounded transition-all ${
                copied 
                ? 'bg-green-500/20 text-green-400' 
                : 'text-gray-400 hover:text-white hover:bg-primary/20 hover:text-primary'
            }`}
            title="复制到剪贴板"
          >
            {copied ? <Check size={16} /> : <Copy size={16} />}
            <span className="text-xs font-bold uppercase">{copied ? '已复制' : '复制'}</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export const ContentArea: React.FC<ContentAreaProps> = ({ 
    group, 
    onAddItem, 
    onDeleteItem,
    onUpdateItem
}) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [newItemLabel, setNewItemLabel] = useState('');
  const [newItemValue, setNewItemValue] = useState('');
  const [newItemType, setNewItemType] = useState<ItemType>('text');
  const [isGridView, setIsGridView] = useState(true);

  // Reset form when group changes
  useEffect(() => {
    setIsAdding(false);
    setNewItemLabel('');
    setNewItemValue('');
  }, [group?.id]);

  if (!group) {
    return (
      <div className="flex-1 h-full bg-background flex items-center justify-center p-8">
        <div className="text-center max-w-md">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-surface mb-6">
                <Terminal size={32} className="text-gray-600" />
            </div>
            <h1 className="text-2xl font-bold text-gray-300 mb-2">欢迎使用 ConfigVault</h1>
            <p className="text-gray-500 mb-8">请从左侧选择一个项目和分组，以查看或管理您的配置密钥。</p>
        </div>
      </div>
    );
  }

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const handleAddItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (newItemLabel && newItemValue) {
      onAddItem({
        id: crypto.randomUUID(),
        label: newItemLabel,
        value: newItemValue,
        type: newItemType
      });
      setNewItemLabel('');
      setNewItemValue('');
      setIsAdding(false);
    }
  };

  const handleSmartImport = (items: ParsedItem[]) => {
      items.forEach(item => {
          onAddItem({
              id: crypto.randomUUID(),
              label: item.label,
              value: item.value,
              type: item.type
          });
      });
  };

  return (
    <div className="flex-1 h-full flex flex-col bg-background relative">
      <ImportModal 
        isOpen={isImporting} 
        onClose={() => setIsImporting(false)} 
        onImport={handleSmartImport}
      />

      {/* Header */}
      <div className="p-6 pb-4 border-b border-border flex items-center justify-between sticky top-0 bg-background/95 backdrop-blur z-10 gap-4">
        <div className="flex-1 overflow-hidden">
           <div className="flex items-center gap-2 text-xs text-gray-500 uppercase tracking-widest mb-1">
                <span>配置列表</span>
                <span>/</span>
                <span className="text-primary truncate">{group.name}</span>
           </div>
           <h1 className="text-xl font-bold text-white truncate">{group.name}</h1>
        </div>

        <div className="flex items-center gap-2 flex-shrink-0">
            {/* View Toggle */}
            <div className="bg-surface border border-border rounded-lg p-1 flex items-center hidden sm:flex">
                <button
                    onClick={() => setIsGridView(false)}
                    className={`p-1.5 rounded transition-colors ${!isGridView ? 'bg-primary text-white shadow' : 'text-gray-400 hover:text-white'}`}
                    title="列表视图"
                >
                    <List size={18} />
                </button>
                <button
                    onClick={() => setIsGridView(true)}
                    className={`p-1.5 rounded transition-colors ${isGridView ? 'bg-primary text-white shadow' : 'text-gray-400 hover:text-white'}`}
                    title="网格视图"
                >
                    <LayoutGrid size={18} />
                </button>
            </div>

            <button
                onClick={() => setIsImporting(true)}
                className="flex items-center gap-2 px-3 py-2 rounded-md text-sm font-medium bg-surface hover:bg-white/10 text-primary border border-primary/20 transition-all"
                title="智能导入"
            >
                <Sparkles size={18} />
                <span className="hidden sm:inline">智能导入</span>
            </button>

            <button
                onClick={() => setIsAdding(!isAdding)}
                className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${
                    isAdding 
                    ? 'bg-gray-700 text-gray-300 hover:bg-gray-600' 
                    : 'bg-primary text-white hover:bg-blue-600 shadow-lg shadow-blue-900/20'
                }`}
            >
                {isAdding ? '取消' : (
                    <>
                        <Plus size={18} />
                        <span className="hidden sm:inline">新建</span>
                    </>
                )}
            </button>
        </div>
      </div>

      {/* Content Scroll Area */}
      <div className="flex-1 overflow-y-auto p-6">

        {/* Add Form */}
        {isAdding && (
          <form onSubmit={handleAddItem} className="bg-surface/50 border border-primary border-dashed rounded-lg p-4 mb-6 animate-in slide-in-from-top-4 fade-in duration-300">
             <div className="flex flex-col md:flex-row items-start md:items-center gap-4 mb-3">
                 <div className="flex-1 w-full">
                     <label className="block text-xs text-gray-500 mb-1">名称</label>
                     <input 
                        autoFocus
                        required
                        className="w-full bg-background border border-border rounded px-3 py-2 text-sm focus:border-primary focus:outline-none"
                        placeholder="例如：DATABASE_URL"
                        value={newItemLabel}
                        onChange={e => setNewItemLabel(e.target.value)}
                     />
                 </div>
                 <div className="w-full md:w-1/3">
                    <label className="block text-xs text-gray-500 mb-1">类型</label>
                     <div className="flex bg-background border border-border rounded p-1">
                        {(['text', 'password', 'code'] as ItemType[]).map(t => (
                            <button
                                key={t}
                                type="button"
                                onClick={() => setNewItemType(t)}
                                className={`flex-1 text-xs py-1.5 rounded capitalize ${newItemType === t ? 'bg-surface text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}
                            >
                                {t}
                            </button>
                        ))}
                     </div>
                 </div>
             </div>

             <div className="mb-4">
                <label className="block text-xs text-gray-500 mb-1">内容</label>
                <textarea 
                    required
                    className="w-full bg-background border border-border rounded px-3 py-2 text-sm font-mono h-20 focus:border-primary focus:outline-none resize-none"
                    placeholder="在此输入密钥值或代码片段..."
                    value={newItemValue}
                    onChange={e => setNewItemValue(e.target.value)}
                />
             </div>

             <div className="flex justify-end">
                 <button type="submit" className="bg-primary hover:bg-blue-600 text-white px-4 py-1.5 rounded text-sm font-medium transition-colors">
                     添加
                 </button>
             </div>
          </form>
        )}

        {/* List / Grid */}
        <div className={isGridView ? "grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4" : "space-y-2"}>
            {group.items.length === 0 && !isAdding && (
                <div className={`flex flex-col items-center justify-center py-12 text-gray-500 border-2 border-dashed border-border rounded-xl ${isGridView ? 'col-span-full' : ''}`}>
                    <Key size={32} className="mb-3 opacity-20" />
                    <p>此分组暂无内容。</p>
                </div>
            )}

            {group.items.map(item => (
                <ItemCard 
                    key={item.id} 
                    item={item} 
                    onCopy={handleCopy} 
                    onDelete={() => onDeleteItem(item.id)}
                    onUpdate={(updates) => onUpdateItem(item.id, updates)}
                    isGridView={isGridView}
                />
            ))}
        </div>
      </div>
    </div>
  );
};
